{
  "name": "OnlyJam",
  "description": "A social music app for real-time collaborative listening sessions. Create Jams, share QR codes, and build playlists together."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  name: string;
  avatar: string;
  isHost: boolean;
}

export interface Song {
  id: string;
  title: string;
  artist: string;
  coverUrl: string;
  source: 'Spotify' | 'YouTube';
  votes: number;
  addedBy: string;
  duration: string;
}

export interface JamSession {
  id: string;
  hostId: string;
  isActive: boolean;
  code: string;
  nowPlaying?: Song;
  queue: Song[];
  settings: {
    votingEnabled: boolean;
    guestUploads: boolean;
    explicitFilter: boolean;
  };
}

export enum ViewState {
  LANDING = 'LANDING',
  AUTH = 'AUTH',
  HOME = 'HOME',
  HOST_PANEL = 'HOST_PANEL',
  GUEST_JOIN = 'GUEST_JOIN',
  PLAYER = 'PLAYER',
  PROFILE = 'PROFILE'
}

import { JamSession, Song } from '../types';
import { MOCK_SONGS } from '../constants';

// Simulating a backend service
export const createJam = (hostId: string): JamSession => {
  return {
    id: `JAM-${Math.floor(1000 + Math.random() * 9000)}`,
    hostId,
    isActive: true,
    code: '8821',
    nowPlaying: MOCK_SONGS[0],
    queue: MOCK_SONGS.slice(1),
    settings: {
      votingEnabled: true,
      guestUploads: false,
      explicitFilter: false
    }
  };
};

export const searchSongs = (query: string): Song[] => {
  if (!query) return MOCK_SONGS;
  const lowerQuery = query.toLowerCase();
  return MOCK_SONGS.filter(s => 
    s.title.toLowerCase().includes(lowerQuery) || 
    s.artist.toLowerCase().includes(lowerQuery)
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'icon';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-semibold transition-colors duration-200 rounded-full";

  const variants = {
    primary: "bg-brand-red text-white hover:bg-red-700 px-6 py-3",
    secondary: "bg-brand-gray text-white hover:bg-zinc-700 px-6 py-3",
    ghost: "bg-transparent text-white border border-white/20 hover:bg-white/10 px-6 py-3",
    icon: "p-2 rounded-full hover:bg-white/10 text-white"
  };

  const widthStyle = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${widthStyle} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

