// --- Main App Component ---

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.LANDING);
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<JamSession | null>(null);
  const [showHostPanel, setShowHostPanel] = useState(false);

  // Initialize simulated session for host flow
  const startSession = () => {
    const newUser = { ...MOCK_USER, isHost: true };
    setUser(newUser);
    setSession(createJam(newUser.id));
    setView(ViewState.PLAYER); // Go straight to player, can open host panel later
    // In a real app, maybe go to HOST_PANEL first or show it immediately
    setShowHostPanel(true);
  };

  const joinSession = () => {
      const newUser = { ...MOCK_USER, isHost: false };
      setUser(newUser);
      // Simulate joining existing
      setSession(createJam('host_123'));
      setView(ViewState.PLAYER);
  };

  const handleAddSong = (song: Song) => {
      if (!session) return;
      const newSong = { ...song, addedBy: user?.name || 'Guest', votes: 1, id: Math.random().toString() };
      setSession(prev => prev ? {
          ...prev,
          queue: [...prev.queue, newSong]
      } : null);
      // Optional: Show toast
      setView(ViewState.PLAYER);
  };

  // Render Logic
  const renderView = () => {
    switch(view) {
      case ViewState.LANDING:
        return <LandingPage onStart={() => setView(ViewState.AUTH)} />;
      case ViewState.AUTH:
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center p-6 animate-fade-in">
                 <h2 className="text-3xl font-bold mb-8 text-center">Welcome to <br/> Only<span className="text-brand-red">Jam</span></h2>
                 <div className="w-full max-w-sm space-y-4">
                     <Button onClick={startSession} fullWidth className="bg-gradient-to-r from-brand-red to-orange-600">Start a Jam (Host)</Button>
                     <div className="text-center text-gray-500 text-sm py-2">OR</div>
                     <Button onClick={joinSession} variant="secondary" fullWidth>Join a Jam (Guest)</Button>
                 </div>
            </div>
        );
      case ViewState.PLAYER:
