                     <div className="bg-zinc-900 p-4 rounded-xl flex items-center justify-between">
                         <span>History</span>
                         <ArrowRight size={16} className="text-gray-500" />
                     </div>
                     <div className="bg-zinc-900 p-4 rounded-xl flex items-center justify-between">
                         <span>Settings</span>
                         <Settings size={16} className="text-gray-500" />
                     </div>
                </div>

                <Button variant="ghost" className="mt-auto text-red-500 border-red-900/30 hover:bg-red-900/10" onClick={() => setView(ViewState.LANDING)}>
                    Log Out
                </Button>
            </div>
        );
      default:
        return <div>View Not Found</div>;
    }
  };

  return (
    <div className="bg-black text-white min-h-screen font-sans selection:bg-brand-red selection:text-white">
      {renderView()}

      {/* Overlays */}
      {showHostPanel && session && (
          <HostPanel session={session} onClose={() => setShowHostPanel(false)} />
      )}

      {/* Navigation (Only show if authenticated) */}
      {view !== ViewState.LANDING && view !== ViewState.AUTH && (
          <Navigation currentView={view} onChangeView={setView} />
      )}
    </div>
  );
};

