const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.LANDING);
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<JamSession | null>(null);
  const [showHostPanel, setShowHostPanel] = useState(false);

  // Initialize simulated session for host flow
  const startSession = () => {
    const newUser = { ...MOCK_USER, isHost: true };
    setUser(newUser);
    setSession(createJam(newUser.id));
    setView(ViewState.PLAYER); // Go straight to player, can open host panel later
    // In a real app, maybe go to HOST_PANEL first or show it immediately
    setShowHostPanel(true);
  };

  const joinSession = () => {
      const newUser = { ...MOCK_USER, isHost: false };
      setUser(newUser);
      // Simulate joining existing
      setSession(createJam('host_123'));
      setView(ViewState.PLAYER);
  };

  const handleAddSong = (song: Song) => {
      if (!session) return;
      const newSong = { ...song, addedBy: user?.name || 'Guest', votes: 1, id: Math.random().toString() };
      setSession(prev => prev ? {
          ...prev,
          queue: [...prev.queue, newSong]
      } : null);
      // Optional: Show toast
      setView(ViewState.PLAYER);
  };

  // Render Logic
  const renderView = () => {
    switch(view) {
      case ViewState.LANDING:
        return <LandingPage onStart={() => setView(ViewState.AUTH)} />;
      case ViewState.AUTH:
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center p-6 animate-fade-in">
                 <h2 className="text-3xl font-bold mb-8 text-center">Welcome to <br/> Only<span className="text-brand-red">Jam</span></h2>
                 <div className="w-full max-w-sm space-y-4">
                     <Button onClick={startSession} fullWidth className="bg-gradient-to-r from-brand-red to-orange-600">Start a Jam (Host)</Button>
                     <div className="text-center text-gray-500 text-sm py-2">OR</div>
                     <Button onClick={joinSession} variant="secondary" fullWidth>Join a Jam (Guest)</Button>
                 </div>
            </div>
        );
      case ViewState.PLAYER:
      case ViewState.HOST_PANEL: // Host panel is an overlay on Player
        return <PlayerView 
            session={session} 
            isHost={user?.isHost || false} 
            onOpenHostPanel={() => setShowHostPanel(true)} 
        />;
      case ViewState.GUEST_JOIN: // Re-using as Search/Home for Guest
      case ViewState.HOME: // "Home" maps to Search in this simplified flow
        return <SearchView onAddSong={handleAddSong} />;
      case ViewState.PROFILE:
        return (
            <div className="h-full bg-black p-6 pb-24 flex flex-col items-center pt-12">
                <div className="w-24 h-24 rounded-full bg-zinc-800 mb-4 overflow-hidden border-2 border-brand-red">
                    <img src={user?.avatar} alt="Profile" className="w-full h-full object-cover" />
                </div>
                <h2 className="text-2xl font-bold text-white mb-1">{user?.name}</h2>
                <p className="text-brand-red text-sm font-semibold mb-8">{user?.isHost ? 'Host' : 'Music Enthusiast'}</p>

                <div className="w-full max-w-sm space-y-4">
                     <div className="bg-zinc-900 p-4 rounded-xl flex items-center justify-between">
                         <span>Your Playlists</span>
                         <ArrowRight size={16} className="text-gray-500" />
                     </div>
                     <div className="bg-zinc-900 p-4 rounded-xl flex items-center justify-between">
                         <span>History</span>
                         <ArrowRight size={16} className="text-gray-500" />
                     </div>
                     <div className="bg-zinc-900 p-4 rounded-xl flex items-center justify-between">
                         <span>Settings</span>
                         <Settings size={16} className="text-gray-500" />
                     </div>
                </div>

                <Button variant="ghost" className="mt-auto text-red-500 border-red-900/30 hover:bg-red-900/10" onClick={() => setView(ViewState.LANDING)}>
                    Log Out
                </Button>
            </div>
        );
      default:
        return <div>View Not Found</div>;
    }
  };

  return (
    <div className="bg-black text-white min-h-screen font-sans selection:bg-brand-red selection:text-white">
      {renderView()}

      {/* Overlays */}
      {showHostPanel && session && (
          <HostPanel session={session} onClose={() => setShowHostPanel(false)} />
      )}

      {/* Navigation (Only show if authenticated) */}
      {view !== ViewState.LANDING && view !== ViewState.AUTH && (
          <Navigation currentView={view} onChangeView={setView} />
      )}
    </div>
  );
};

